const clamp = (num, min, max) => Math.min(Math.max(num, min), max);

const linearScale = (value, inputMin, inputMax, outputMin, outputMax) => {
    if (value <= inputMin) return outputMin;
    if (value >= inputMax) return outputMax;
    return outputMin + (value - inputMin) * (outputMax - outputMin) / (inputMax - inputMin);
};

let score = 0;

// 1. ICU Bed Capacity (per 100,000 residents) - Max 15 points
// Target: 15 beds/100k for full points. Min 5 for any points. Capped at 20 for calculation.
const icuBedScore = linearScale(clamp(inputs.icuBedCapacityPer100k, 0, 20), 5, 15, 0, 15);
score += icuBedScore;

// 2. Healthcare Worker Availability (per 1,000 residents) - Max 15 points
// Target: 15 HCW/1k for full points. Min 5 for any points. Capped at 20 for calculation.
const hcwScore = linearScale(clamp(inputs.hcwAvailabilityPer1k, 0, 20), 5, 15, 0, 15);
score += hcwScore;

// 3. Critical PPE Stockpile (Days Supply) - Max 15 points
// Target: 90 days for full points. Min 30 for any points. Capped at 120 for calculation.
const ppeScore = linearScale(clamp(inputs.ppeStockpileDays, 0, 120), 30, 90, 0, 15);
score += ppeScore;

// 4. Key Disease Vaccination Coverage (%) - Max 20 points
// Target: 90% for full points. Min 60% for any points. Capped at 100 for calculation.
const vaccinationScore = linearScale(clamp(inputs.vaccinationCoverage, 0, 100), 60, 90, 0, 20);
score += vaccinationScore;

// 5. Emergency Communication System Effectiveness (Score 1-5) - Max 10 points
// Linear scale: 1=0 points, 5=10 points. Clamped by input rules.
const commScore = linearScale(inputs.commSystemScore, 1, 5, 0, 10);
score += commScore;

// 6. Disaster Plan Review Frequency (months, lower is better) - Max 10 points
// Target: 6 months or less for full points. 24 months for 0 points. Capped at 36 for calculation.
const planReviewScore = linearScale(clamp(inputs.planReviewFrequencyMonths, 1, 36), 24, 6, 0, 10);
score += planReviewScore;

// 7. Isolation/Quarantine Capacity (beds per 100,000 residents) - Max 15 points
// Target: 8 beds/100k for full points. Min 2 for any points. Capped at 15 for calculation.
const isolationScore = linearScale(clamp(inputs.isolationCapacityPer100k, 0, 15), 2, 8, 0, 15);
score += isolationScore;

// Ensure total score is within 0-100 range
score = clamp(score, 0, 100);

// Determine category and recommendation
let scoreCategory = "";
let recommendation = "";

if (score >= 86) {
    scoreCategory = "Exemplary Readiness";
    recommendation = "Your community demonstrates exemplary readiness for public health emergencies, with robust infrastructure and protocols. Focus on continuous improvement and consider serving as a model for other regions.";
} else if (score >= 71) {
    scoreCategory = "Strong Preparedness";
    recommendation = "Your community is strongly prepared for public health emergencies. Identify minor areas for optimization, such as refining specific protocols or enhancing certain resource stockpiles, to achieve exemplary status.";
} else if (score >= 51) {
    scoreCategory = "Moderate Preparedness";
    recommendation = "Your community shows moderate preparedness. Prioritize addressing identified gaps, especially in resource availability, infrastructure capacity, or specific protocol areas, to enhance overall resilience.";
} else if (score >= 31) {
    scoreCategory = "Significant Gaps";
    recommendation = "Your community has significant gaps in its emergency preparedness. Immediate attention and strategic investment are required across multiple areas to mitigate substantial risks and establish foundational readiness.";
} else {
    scoreCategory = "Critical Vulnerability";
    recommendation = "Your community is critically vulnerable to public health emergencies. Urgent, comprehensive intervention and significant resource allocation are imperative to establish foundational preparedness and protect public health.";
}

return {
    preparednessScore: parseFloat(score.toFixed(1)),
    scoreCategory: scoreCategory,
    recommendation: recommendation
};
